  // Single Line Diagrams
  '2d2b73d8b43a801bb3f6e5e29fa5082b': [
    { q: "What does a Single Line Diagram (SLD) represent for a solar installation?", options: ["A wiring diagram showing every individual conductor and splice","A simplified schematic of the system's main electrical components, their relationships, and the flow of power — used for design, permitting, and inspection","A floor plan of the property with panel locations marked","A timeline of the installation process"], correct: 1 },
    { q: "When is a Single Line Diagram typically required?", options: ["Only for systems over 100 kW","For electrical permitting, utility interconnection applications, and inspection — most jurisdictions require an SLD as part of the permit package","SLDs are optional and only produced if the inspector requests one","Only for three-phase commercial systems"], correct: 1 },
    { q: "Who at Solve Energy is responsible for producing or verifying the Single Line Diagram for a project?", options: ["The roof installation crew","A qualified electrical designer or licensed electrician, reviewed and signed off before permit submission","Any team member familiar with the site","The customer's utility provider"], correct: 1 },
    { q: "An SLD shows a solar system connected with a 20A breaker in the main panel. During install the crew discovers the panel's available breaker space is insufficient. What must happen?", options: ["Install the breaker wherever it will fit and update the SLD later","Reduce the system size to fit the existing space without updating design documents","Do not proceed with installation until the SLD and permit are updated to reflect the revised design — installing outside the approved permit drawings is a code violation","Ask the customer if they are comfortable with the change and proceed with their verbal approval"], correct: 2 },
    { q: "Why is it important that an SLD shows the correct conductor sizes, not just the component layout?", options: ["Conductor sizes are optional on residential SLDs — only required commercially","Conductor sizes on the SLD must match what is installed so the inspector can verify code compliance — undersized conductors are a fire hazard and the inspector will reject the permit if sizes are incorrect or missing","Conductor sizes are only checked by the manufacturer, not the AHJ inspector","The SLD is only a schematic — actual wire sizes are the electrician's choice on site"], correct: 1 },
    { q: "What is the key difference between a Single Line Diagram and a full schematic wiring diagram?", options: ["They are the same document with different names","An SLD shows one representative line for each circuit regardless of conductor count, focusing on system topology and protection devices — a full schematic shows every individual conductor, connection, and termination point","An SLD is used during design; a full schematic is only used during commissioning","Full schematics are required by BC Hydro; SLDs are only used by electricians"], correct: 3 }
  ],

