// Generic fallback quiz for any unmapped blocks
function genericQuiz(blockName) {
  return [
    {
      q: `Have you reviewed the training material for "${blockName}"?`,
      options: ["No — I have not reviewed it","Yes — I have read and understood the material","I will review it later","It is not relevant to my role"],
      correct: 1
    },
    {
      q: `If you have questions about "${blockName}" after completing this training, you should:`,
      options: ["Ignore any uncertainties","Ask your supervisor or manager for clarification","Assume your understanding is correct","Wait until your next performance review"],
      correct: 1
    }
  ];
}

